-- V1 Initial Schema Bootstrap
-- Creates ALL foundational tables that were originally auto-generated by Hibernate ddl-auto.
-- Required for fresh local database setup since all subsequent migrations assume these exist.

-- 1. Clients (Tenant level)
CREATE TABLE IF NOT EXISTS clients (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(255),
    email VARCHAR(255),
    phone VARCHAR(50),
    country VARCHAR(100),
    pos_type VARCHAR(50),
    subscription_status VARCHAR(50),
    stripe_customer_id VARCHAR(255),
    subscription_expiry_date TIMESTAMP,
    primary_language VARCHAR(50) DEFAULT 'English',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(255)
);

-- 2. Organizations (Branch level)
CREATE TABLE IF NOT EXISTS organizations (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(255),
    address TEXT,
    phone VARCHAR(50),
    google_maps_url VARCHAR(1024),
    pin_code VARCHAR(20),
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(255)
);

-- 3. Users
CREATE TABLE IF NOT EXISTS users (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    first_name VARCHAR(255),
    last_name VARCHAR(255),
    email VARCHAR(255) UNIQUE NOT NULL,
    password VARCHAR(255) NOT NULL,
    is_enabled BOOLEAN NOT NULL DEFAULT TRUE,
    client_id UUID,
    org_id UUID,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(255)
);

-- 4. Categories
CREATE TABLE IF NOT EXISTS categories (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(255),
    description TEXT,
    is_active BOOLEAN DEFAULT TRUE,
    image_url VARCHAR(255),
    client_id UUID,
    org_id UUID,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(255)
);

-- 5. Products
CREATE TABLE IF NOT EXISTS products (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(255),
    description TEXT,
    price NUMERIC(15,2) NOT NULL DEFAULT 0,
    is_available BOOLEAN DEFAULT TRUE,
    image_url TEXT,
    client_id UUID,
    org_id UUID,
    product_type VARCHAR(50),
    is_variant BOOLEAN DEFAULT FALSE,
    is_packaged_good BOOLEAN DEFAULT FALSE,
    is_ingredient BOOLEAN DEFAULT FALSE,
    product_code VARCHAR(100),
    tax_rate NUMERIC(5,2),
    tax_code VARCHAR(50),
    mrp NUMERIC(15,2),
    cost_price NUMERIC(15,2),
    barcode VARCHAR(255),
    min_stock_level INTEGER,
    kds_station VARCHAR(100),
    is_active BOOLEAN DEFAULT TRUE,
    category_id UUID REFERENCES categories(id),
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(255)
);

-- 6. Orders
CREATE TABLE IF NOT EXISTS orders (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    order_no VARCHAR(255) UNIQUE NOT NULL,
    order_type VARCHAR(20) DEFAULT 'SALE',
    order_status VARCHAR(20) DEFAULT 'DRAFT',
    payment_status VARCHAR(20) DEFAULT 'PENDING',
    order_source VARCHAR(50) DEFAULT 'OFFLINE',
    terminal_id UUID,
    customer_id UUID,
    vendor_id UUID,
    pricelist_id UUID,
    currency_id UUID,
    warehouse_id UUID,
    order_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    total_tax_amount NUMERIC(15,2) DEFAULT 0,
    total_discount_amount NUMERIC(15,2) DEFAULT 0,
    total_amount NUMERIC(15,2) DEFAULT 0,
    grand_total NUMERIC(15,2) DEFAULT 0,
    description TEXT,
    reference VARCHAR(100),
    fulfillment_type VARCHAR(20) DEFAULT 'DINE_IN',
    table_number VARCHAR(20),
    isactive VARCHAR(1) DEFAULT 'Y',
    client_id UUID,
    org_id UUID,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(255)
);

-- 7. Order Items / Order Lines
CREATE TABLE IF NOT EXISTS order_items (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    order_id UUID REFERENCES orders(id),
    product_id UUID,
    variant_id UUID,
    quantity NUMERIC(15,3) DEFAULT 1,
    unit_of_measure VARCHAR(20) DEFAULT 'units',
    unit_price NUMERIC(15,2) NOT NULL,
    tax_rate NUMERIC(5,2) DEFAULT 0,
    tax_amount NUMERIC(15,2) DEFAULT 0,
    discount_amount NUMERIC(15,2) DEFAULT 0,
    line_total NUMERIC(15,2) NOT NULL,
    isactive VARCHAR(1) DEFAULT 'Y',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    created_by UUID,
    updated_by UUID
);

-- Also create order_lines (the entity actually maps to this)
CREATE TABLE IF NOT EXISTS order_lines (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    order_id UUID REFERENCES orders(id),
    product_id UUID,
    variant_id UUID,
    quantity NUMERIC(15,3) DEFAULT 1,
    unit_of_measure VARCHAR(20) DEFAULT 'units',
    unit_price NUMERIC(15,2) NOT NULL,
    tax_rate NUMERIC(5,2) DEFAULT 0,
    tax_amount NUMERIC(15,2) DEFAULT 0,
    discount_amount NUMERIC(15,2) DEFAULT 0,
    line_total NUMERIC(15,2) NOT NULL,
    isactive VARCHAR(1) DEFAULT 'Y',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    created_by UUID,
    updated_by UUID
);

-- 8. Invoices
CREATE TABLE IF NOT EXISTS invoices (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    terminal_id UUID,
    order_id UUID,
    customer_id UUID,
    vendor_id UUID,
    invoice_no VARCHAR(255) UNIQUE NOT NULL,
    invoice_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    due_date TIMESTAMP,
    status VARCHAR(20) DEFAULT 'UNPAID',
    is_paid BOOLEAN DEFAULT FALSE,
    total_amount NUMERIC(15,2) NOT NULL DEFAULT 0,
    amount_due NUMERIC(15,2) NOT NULL DEFAULT 0,
    description TEXT,
    reference VARCHAR(100),
    isactive VARCHAR(1) DEFAULT 'Y',
    client_id UUID,
    org_id UUID,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_by VARCHAR(255)
);
